var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"으음...","JPN":"うーん……","ENG":"Mm...","TWN":"嗯……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"앗... 여긴...?","JPN":"こ……ここは……？","ENG":"Huh...? Where am I...?","TWN":"咦……這裡是……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L4_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이제 좀 괜찮아요?","JPN":"少しは楽になりましたか？","ENG":"Are you feeling a little better now?","TWN":"你現在覺得舒服點了嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"엄청 늦잠 잤네요.","JPN":"大寝坊ですよ。","ENG":"You really overslept.","TWN":"你睡得可真久呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"...니콜?","JPN":"……ニコル？","ENG":"...Nicole?","TWN":"……妮可？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"무서운 일이 있었도다. 이 몸이 못된 녀석한테 붙잡혀서...","JPN":"怖いことがあったのだ。吾輩が悪い奴に捕まって……","ENG":"A dreadful thing happened. I was captured by a wicked one...","TWN":"剛剛發生了很可怕的事，我被壞人抓走了……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"...영영 돌아오지 못할 뻔했었죠.","JPN":"……永遠に帰ってこられなくなるところでしたね。","ENG":"...You almost never made it back.","TWN":"……差點就永遠回不來了呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"하지만 이제 걱정 말아요. 모모를 괴롭히던 못된 마왕은 이제 사라졌으니까.","JPN":"でももう心配しなくて大丈夫です。モモをいじめていた悪い魔王は消えましたから。","ENG":"But you don't have to worry anymore. The wicked Demon Lord who was tormenting you is gone now.","TWN":"不過現在不用擔心了，欺負莫莫的壞魔王已經不在了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그게 무슨 소리냐. 마왕은...","JPN":"何を言っている？　魔王は……","ENG":"What are you saying? I...","TWN":"那是什麼意思？魔王不是……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"...마왕은, 바로 이 몸이지 않더냐.","JPN":"……魔王は、吾輩ではないか。","ENG":"...I am the Demon Lord.","TWN":"……魔王，不就是我嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"물론 모모는 마왕님이죠. 하지만 세상을 멸망시키려던 타기리온은 아녜요.","JPN":"もちろん、モモは魔王ですよ。でも世界を滅ぼそうとしていたタギリオンではありません。","ENG":"Of course you are, Momo. But you're not Thagirion, the one who tried to destroy the world.","TWN":"莫莫當然是魔王，但並不是那個想毀滅世界的塔基里翁。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그 사람에게서 떨어져 나온 순수한 마음 중 하나였을 뿐이죠.","JPN":"彼女が持っていた、純粋な心の一つだっただけです。","ENG":"You were only one of the pure pieces of her heart.","TWN":"那只是她擁有的純真的一部分而已。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그치만 모모는...","JPN":"しかし、モモは……","ENG":"But Momo is...","TWN":"可是莫莫……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"...모드레드가 알고 있던 모르가나가 아닌걸.","JPN":"……モードレッドが知っていたモルガナではないぞ。","ENG":"...Not the Morgana that Mordred once knew.","TWN":"……並不是莫德雷認識的莫甘娜。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"저도 모드레드가 아녜요. 니콜 프라이머죠.","JPN":"私はモードレッドじゃありません。ニコル・プライマーです。","ENG":"I'm not Mordred. I'm Nicole Primer.","TWN":"我不是莫德雷。我是妮可．布萊伊莫。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그리고 모모는 모모고요. 변한 건 아무것도 없어요.","JPN":"そしてモモはモモです。何も変わっていませんよ。","ENG":"And you're Momo. Nothing about that has changed.","TWN":"而莫莫就是莫莫，什麼都沒有改變。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"정말... 그걸로 괜찮은 것이냐?","JPN":"本当に……それでいいのか？","ENG":"Are you sure... you're okay with that?","TWN":"真的……可以這樣嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그 모르가나란 소녀도, 니콜이 누구인지 모르던 걸요?","JPN":"そのモルガナって子も、ニコルが誰なのか知らなかったんですよ？","ENG":"That girl Morgana didn't even know who Nicole was either.","TWN":"那個叫莫甘娜的孩子，也不知道妮可是誰啊？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"전생의 기억이니, 운명 같은 건 처음부터 중요하지 않았어요. 제가 데려오고 싶었던 사람은 처음부터 모모였으니까.","JPN":"前世の記憶とか運命とか、そんなものは最初からどうでもよかったんです。私が連れ戻したかったのは最初からモモでしたから。","ENG":"Memories of a past life, fate, things like that were never what mattered. The one I wanted to bring back from the start was you, Momo.","TWN":"既然只是前世的記憶，命運之類的東西從一開始就不重要。我想帶回來的人，從一開始就只有莫莫而已。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"정말로......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"보고 싶었도다. 니콜.","JPN":"会いたかったぞ、ニコル。","ENG":"I missed you, Nicole.","TWN":"我好想你啊，妮可。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"...저도요.","JPN":"……私もです。","ENG":"...I missed you too.","TWN":"……我也是。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이제 우리, 다신 헤어지지 말아요.","JPN":"これからはずっと一緒ですよ、私たち。","ENG":"Let's never leave each other's side from now on.","TWN":"以後就一直在一起吧，我們。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"앗.","JPN":"あっ。","ENG":"Ah.","TWN":"啊。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"다녀오셨어요?","JPN":"お帰りになってたんですか？","ENG":"You're back.","TWN":"你回來啦？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"...그래.","JPN":"……ええ。","ENG":"...Yes.","TWN":"……嗯。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"두 사람도, 먼 길 다녀오느라 고생 많았어.","JPN":"二人も、長旅お疲れさま。","ENG":"You two must have had a long journey as well. Good work making it back.","TWN":"你們兩個跑這麼遠也辛苦了。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"...이상으로, 도시관리국 별 정례보고를 마치겠습니다.","JPN":"……以上、各都市管理局の定期報告を終わります。","ENG":"...That concludes the regular regional report from the City Management.","TWN":"……以上是城市管理局本次的定期報告。"},"stage":{"bg":"OMEN_G1_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 다들 수고 많았네.","JPN":"ああ、皆ご苦労だった。","ENG":"Okay. Good job, everyone.","TWN":"好。大家都辛苦了。"},"stage":{"bg":"OMEN_G1_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"당분간은 모두들 재난 수복에 힘써주게나.","JPN":"今後も引き続き修復に力を尽くしてくれ。","ENG":"Please continue prioritizing the city's restoration efforts.","TWN":"今後也請繼續努力進行修復工作。"},"stage":{"bg":"OMEN_G1_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"저기, 관리자.","JPN":"ねえ、管理者。","ENG":"Excuse me, Administrator.","TWN":"那個，管理員。"},"stage":{"bg":"OMEN_G1_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"듣고 있네, 이졸데.","JPN":"何かね、イゾルデ君。","ENG":"Yes, Isolde?","TWN":"你說吧，伊索德。"},"stage":{"bg":"OMEN_G1_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그럼, 탐미엘을 비롯한 다른 마왕들은 여전히 우리 세계를 노리고 있다는 거지? ","JPN":"じゃあ、タミエルとか他の魔王たちは、まだ私たちの世界を狙ってるってことだよね？ ","ENG":"So Tammiel and the other Demon Lords are still targeting our world? ","TWN":"那麼，包括塔米爾在內的其他魔王，還是會覬覦我們的世界對吧？ "},"stage":{"bg":"OMEN_G1_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 마왕이란 존재가 사라지지 않는 이상, 언젠가 또 이번 사태와 같은 일이 벌어져도 이상하지 않지.","JPN":"ああ。魔王という存在が消えない限り、いつかまた今回のようなことが起きてもおかしくない。","ENG":"I'm afraid so. As long as Demon Lords continue to exist, it wouldn't be surprising if an incident like this happens again someday.","TWN":"沒錯。只要魔王這種存在沒有消失，將來再發生跟這次一樣的事件也不奇怪。"},"stage":{"bg":"OMEN_G1_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 상황이 바뀌었으니, 마왕들도 함부로 우릴 적대하진 않을 걸세.","JPN":"だが、状況が変わったことだし、魔王たちも理由なく我々に敵対することはないだろう。","ENG":"However, circumstances have changed. The Demon Lords are unlikely to oppose us recklessly now.","TWN":"不過情況已經改變了，魔王們也不會輕易與我們為敵。"},"stage":{"bg":"OMEN_G1_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"엑자일러가 함께 공존할 수 있는 세계가 됐다는 건, 마왕들의 입장에서도 예외가 아니기 때문이죠?","JPN":"エグザイラーが共存できる世界になったということは、魔王たちにとっても例外ではないからですよね。","ENG":"Because the world has become one where Exiles and humanity can coexist. That applies to the Demon Lords as well, doesn't it?","TWN":"因為現在已經成為了連流浪者都能共存的世界，這對魔王來說也不是例外吧？"},"stage":{"bg":"OMEN_G1_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L49_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"잘 설득하면, 적으로 싸우지 않고 함께 탐미엘에게 맞설 수도 있을까요?","JPN":"上手く説得すれば、敵としてではなく、一緒にタミエルと戦ってくれることもあるのでしょうか。","ENG":"If we negotiate carefully, could some of them stand with us against Tammiel instead of fighting us as enemies?","TWN":"如果好好說服，說不定能不用戰鬥，而是與他們聯手對抗塔米爾？"},"stage":{"bg":"OMEN_G1_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"...그래. 어쩌면 몇몇 마왕들과는 뜻이 통할지도 모르지.","JPN":"……ああ、もしかすると一部の魔王は協力してくれるかもしれないな。","ENG":"...Yes. It is possible that we may find common ground with a few of them.","TWN":"……是啊。或許可以和某些魔王達成共識。"},"stage":{"bg":"OMEN_G1_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"세피로트 나무가 가진 권한만으로 마왕을 통제할 순 없지만... 권한이 가진 계약의 억제력이라면, 그들이 계약을 무시하고 우릴 배반할 수는 없을 테니.","JPN":"セフィロトの権限だけでは魔王を統制できないが……権限には契約の抑制力があるから、彼らが契約を無視して我々を裏切ることはできないだろう。","ENG":"The authority of the Tree of Sephirot alone can't control the Demon Lords. However, the binding force of its contractual authority would prevent them from violating the agreement and betraying us.","TWN":"雖然不能僅靠生命樹的權限控制魔王……但若以具有權限的契約約束力來說，他們也無法違背契約、背叛我們。"},"stage":{"bg":"OMEN_G1_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"탐미엘을 싫어하는 녀석들로 추려봐야겠네. 그렇지 않고서야 우리와 협력하진 않을 테니까.","JPN":"タミエルを嫌うやつらに絞ってみる必要がありそうだね。そうじゃないと私たちに協力してくれないだろうし。","ENG":"Then we should start by identifying the ones who already dislike Tammiel. Otherwise, they would never cooperate with us.","TWN":"我們得挑選討厭塔米爾的傢伙，不然他們不會願意合作。"},"stage":{"bg":"OMEN_G1_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"지금껏 적이었던 존재와 협력하게 된다면 분명 반발이 따르겠죠.","JPN":"今までは敵だった存在と協力するとなれば、きっと反発があるでしょう。","ENG":"If we end up cooperating with our enemies, there will certainly be resistance.","TWN":"要和過去的敵人合作，肯定會引發反彈。"},"stage":{"bg":"OMEN_G1_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L5_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"인류를 위한 차악으로서 힘을 빌리는 것을 고려할 수 있다... 정도로 이해해두겠습니다.","JPN":"人類のため、奥の手として力を借りることも検討できる……と理解しておきます。","ENG":"I'll understand this as considering the possibility of borrowing their strength as the lesser evil for humanity's sake.","TWN":"就當作是借助他們的力量、為了人類所做的次佳選擇……先這樣理解吧。"},"stage":{"bg":"OMEN_G1_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"물론, 우리 역시 그들이 계약을 받아들일 만한 조건을 제시할 수 있어야 할 걸세.","JPN":"もちろんそうなれば、我々も彼らが契約を受け入れられるだけの条件を提示しなければならない。","ENG":"Of course. We must also be prepared to present terms they would consider acceptable.","TWN":"當然，我們也得提出能讓他們接受契約的條件才行。"},"stage":{"bg":"OMEN_G1_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"당장 마왕과의 협상테이블에 설 만한 적임자가 있긴 하죠.","JPN":"ちょうど魔王との交渉テーブルにつける適任者がいるにはいますね。","ENG":"There is someone suitable to stand at the negotiating table with the Demon Lords right now.","TWN":"目前確實有一位適合與魔王站上談判桌的人選。"},"stage":{"bg":"OMEN_G1_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"최고관리자님께서 아직 그를 충분히 신뢰하신다면 말입니다.","JPN":"最高管理者がまだ彼を信用しているなら、の話ですが。","ENG":"That is, if the Supreme Administrator still trusts him enough.","TWN":"前提是，最高管理者還願意信任那個人。"},"stage":{"bg":"OMEN_G1_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"...그렇군요. 늑대가 사라진 것이 탐미엘의 대적자를 깨우기 위해서였다라.","JPN":"……そうですか。オオカミが消えたのは、タミエルの敵対者を目覚めさせるため……","ENG":"...I see. So the disappearance of the Wolf was meant to awaken Tammiel's Antagonist.","TWN":"……原來如此。狼的消失，是為了喚醒塔米爾的敵對者啊。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"타기리온이 온전한 하나가 아니라는 건 어렴풋이 알고 있었지만, 그녀의 배후에 숨겨진 인격에게 그런 치밀함이 숨겨져 있을 줄은 몰랐군요.","JPN":"タギリオンが完全な形ではないということは薄っすらと勘づいていましたが、隠れされていた彼女のもう一つの人格にそんな緻密な計画があったとは。","ENG":"I had suspected Thagirion wasn't truly whole, but I never imagined such careful design lay hidden within the personality behind her.","TWN":"雖然早就隱約察覺塔基里翁並非完整的一體，但沒想到在她背後的那個人格，竟然如此縝密。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"결과적으로... 저희 마왕님께서도 흡족해하셨습니다.","JPN":"結果的には……私のご主人様も満足されておりました。","ENG":"In any case... our master was quite pleased with the outcome.","TWN":"結論是……我們的魔王也相當滿意。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"다행이군요.","JPN":"安心しました。","ENG":"That's good to hear.","TWN":"那就好。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"스승님이 당신의 주인을 이기는 바람에 기분이 상하신 줄 알았거든요.","JPN":"師匠が勝ってしまったので、機嫌を損ねたのではないかと心配していたんです。","ENG":"I was concerned she might be displeased after my master defeated yours.","TWN":"我還以為師父打敗了你主人，你會不高興呢。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 무슨 말씀을. 결투가는 결투 그 자체를 즐길 뿐 승패에 연연하지 않습니다.","JPN":"ふふ、とんでもありません。決闘家は決闘そのものを楽しむのであって、勝敗は気にしないものです。","ENG":"Haha. Not at all. A duelist enjoys the duel itself. Victory and defeat are secondary.","TWN":"呵呵，怎麼會。決鬥者享受的是決鬥本身，並不執著於勝負。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"오히려 자신을 완전히 끝내지 않고 퇴거시킨 발키리의 자비로운 처사에 실망하셨죠.","JPN":"むしろ自身にトドメを刺さずに退却させた、ヴァルキリーの慈悲にがっかりしていらしたくらいです。","ENG":"If anything, she was disappointed that Valkyrie chose to drive her away instead of finishing her off properly.","TWN":"反而對於女武神沒有徹底了結自己，而是心軟驅逐這件事感到失望呢。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"어이, 잡담은 그쯤하지?","JPN":"おい、雑談はその辺にしたらどうだ？","ENG":"Hey. Enough small talk.","TWN":"喂，閒聊差不多了吧？"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"차 다 마셨으면 여길 찾아온 용무나 말하라고.","JPN":"茶を飲み終わったんなら、ここに来た用件を話せ。","ENG":"If you're done with your tea, say what you came here for.","TWN":"茶都喝完了，就說明你來這裡的目的吧。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"...장기의뢰를 드리려 합니다.","JPN":"……長期の依頼をしたいと思っています。","ENG":"...I would like to request a long-term commission.","TWN":"……我想提出一項長期委託。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"까다로운만큼 충분한 보수도 마련되어 있어요.","JPN":"内容が厄介な分、報酬も弾むつもりです。","ENG":"As difficult as it is, the compensation reflects it.","TWN":"雖然很棘手，但報酬也十分豐厚。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"죄송합니다만, 주인님께선 한동안은 밀린 드라마에 전념하실 예정이랍니다.","JPN":"申し訳ございませんが、ご主人様はしばらくの間、溜まったドラマに専念される予定です。","ENG":"I'm afraid my master intends to devote some time to catching up on her backlog of dramas for the foreseeable future.","TWN":"不好意思，主人最近打算專心補完積欠的戲劇。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"따라서 저희 사무소는 지금, <color=#ffd34c>통상적인</color> 의뢰를 받지 않고 있어요.","JPN":"つきましては、私どもの事務所は現在、通常の依頼は受け付けておりません。","ENG":"As such, our office is not accepting <color=#ffd34c>ordinary</color> requests at the moment.","TWN":"因此本事務所目前暫不接受<color=#ffd34c>一般</color>委託。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"통상적이지 않은 경우는 받아들여질 여지가 있다는 거겠죠?","JPN":"通常ではない場合は、引き受けてもらえる可能性があるという意味ですね？","ENG":"So there may still be room for exceptions, depending on the circumstances?","TWN":"也就是說如果不一般的話，還有機會接受吧？"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"...예외 조건은 단 하나.","JPN":"……例外とする条件はただ一つ。","ENG":"...There is only one condition.","TWN":"……例外條件只有一個。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>의뢰의 타깃이 즐거움을 줄 만큼 충분히 강한가</color>?","JPN":"依頼のターゲットが、楽しませてくれるほど十分に強いか。","ENG":"Is the target of the request <color=#ffd34c>strong enough to provide enjoyment</color>?","TWN":"<color=#ffd34c>委託的目標是否足夠強大，能帶來樂趣</color>？"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그건, 이 자료를 보면서 설명 드리는 편이 빠를 것 같군요.","JPN":"それは、この資料を見せながら説明したほうが早そうですね。","ENG":"In that case, it may be faster if I explain while showing you this material.","TWN":"這一點，我們邊看資料邊直接說明會比較快。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"narration","speaker":null,"text":{"KOREA":"끝이 온다. 늑대는 사라지고, 운명은 거부되었다.","JPN":"深淵が訪れる。オオカミは消え、運命は拒まれた。","ENG":"The end approaches. The Wolf has vanished, and fate has been denied.","TWN":"末日到來。狼已消失，命運遭到拒絕。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"권한자가 우리를 실망시켰으니, 끝으로부터 그가 간다.","JPN":"権限者が我々を失望させたがゆえに、終わりより彼が出向く。","ENG":"The Supervisor has disappointed us. So it comes from the end.","TWN":"既然權限者讓我們失望，那麼就由末日親自降臨。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L39_1","type":"narration","speaker":null,"text":{"KOREA":"존재 중의 존재, 숨은 빛, 첫번째 짐승.","JPN":"存在の中の存在、隠れた光、最初のケモノ。","ENG":"The entity among entities. The hidden light. The First Beast.","TWN":"存在中的存在，隱藏之光，第一之獸。"},"stage":{"bg":"SEPHIROTH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L42_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"첫번째 짐승? 그게 여기로 온다는 뜻인가?","JPN":"最初のケモノ？　それがここに来るってことか？","ENG":"The First Beast? Does that mean it's coming here?","TWN":"第一之獸？你的意思是那東西要來這裡？"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이건, 지중해역의 봉인 대균열로부터 채록된 이상주파의 해독 내용입니다.","JPN":"これは地中海の封印大亀裂から採録された異常周波を解読したものです。","ENG":"This is the decoded content of anomalous frequencies recorded from the sealed Grand Dimension Crevice in the Mediterranean region.","TWN":"這是從地中海域封印的大峽谷中記錄下來的異常頻率解讀內容。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"테라브레인이 인간이 이해할 수 있는 언어로 최대한 의역한 결과죠.","JPN":"テラブレインが人間が理解できる言語に置き換え、最大限に意訳した結果です。","ENG":"Terrabrain produced the closest possible interpretation in a language humans can understand.","TWN":"是特拉大腦盡可能以人類能理解的語言轉譯的結果。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"난해하고 불분명하군요. 확실한 건, 어휘에 분노가 실려 있다는 것 정도네요.","JPN":"難解で不明瞭ですね。確かなのは、語彙に怒りが込められていることぐらいでしょうか。","ENG":"It's obscure and difficult to interpret. The only certainty is the anger carried in its wording.","TWN":"相當晦澀難懂。唯一能確定的是語氣中帶有強烈的憤怒。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이와 같은 언어 패턴은 관리국이 존재하던 다른 세계에서도 해독된 바가 있습니다.","JPN":"このような言語パターンは管理局が存在していた他の世界でも解読された前例があります。","ENG":"This linguistic pattern has also been decoded in other worlds where the Administration once existed.","TWN":"這種語言模式，在管理局曾存在的其他世界中也曾被解讀過。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그리고 <color=#ffd34c>짐승</color>이란 표현과 함께 처음으로 언급되었던 단어가 하나 있더군요.","JPN":"そして、ケモノという表現と共に初めて言及された単語があります。","ENG":"And there was one word that appeared for the first time alongside the term <color=#ffd34c>Beast</color>.","TWN":"而在提到<color=#ffd34c>野獸</color>這個詞時，曾經第一次出現過一個關鍵字。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"심연.","JPN":"深淵。","ENG":"The Abyss.","TWN":"深淵。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"들어본 적이 있습니다.","JPN":"聞いたことがあります。","ENG":"I've heard of it.","TWN":"我有聽過。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"호수의 탐식자와 바티칸의 배교자들, 그리고 검은 죽음이 섬기는 존재이죠.","JPN":"湖の貪食者とバチカンの背教者たち、そして黒い死が仕える存在ですね。","ENG":"It is the being served by the Devourer of the Lake, the Apostates of the Vatican, and the Black Death.","TWN":"湖之吞噬者、梵蒂岡的叛教者，以及黑死侍奉的存在。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 과연.","JPN":"おお……なるほど。","ENG":"Oh my.","TWN":"喔喔，原來如此。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"검은 죽음의 목적이 심연을 불러들이는 것이라면, 타기리온의 계획에 관여한 이유도 납득이 가는군요. 흥미롭네요. 음, 흥미로워요.","JPN":"黒い死の目的が深淵を呼び寄せることなら、タギリオンの計画に関わった理由も合点が行きます。興味深い……実に興味深いですね。","ENG":"If the Black Death seeks to summon the Abyss, then its involvement in Thagirion's plan makes perfect sense. Fascinating. Truly fascinating.","TWN":"如果黑死的目的是召喚深淵，那麼他們介入塔基里翁的計畫也說得通了。嗯，真有意思。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"저희는 이 짐승에 대한 단서를 얻기 위해, 그와 연결된 자들을 만나보려 합니다.","JPN":"僕たちはこのケモノに関する手がかりを得るために、彼と繋がりのある者に接触を試みるつもりです。","ENG":"To obtain clues about this Beast, we intend to meet those connected to him.","TWN":"為了取得這隻野獸的線索，我們打算接觸與其有所關聯的人。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"검은 죽음과 정면으로 충돌하겠군요. 그 배후엔 첫번째 짐승이 있을 테고요.","JPN":"黒い死との全面対決になりそうですね。その背後には最初のケモノがいるはずです。","ENG":"So you plan to confront the Black Death directly. And behind him stands the First Beast.","TWN":"也就是說，會正面與黑死起衝突。而其背後，恐怕就是第一之獸。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이 정도면, 의뢰를 승낙할 요건에 부합할까요?","JPN":"この程度なら、依頼を引き受けてもらう条件として十分でしょうか？","ENG":"Would that satisfy the conditions required to accept this commission?","TWN":"這樣的條件，足以讓你們接受委託了嗎？"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"당신의 주인에게 이렇게 전해주겠습니까?","JPN":"あなたのボスにこうお伝えください。","ENG":"Would you deliver a message to your master for me?","TWN":"可以幫我轉告你的主人嗎？"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>긍정적으로 검토한 다음, 찾아가겠다</color>... 라고.","JPN":"前向きに検討した後、伺います……と。","ENG":"Tell her <color=#ffd34c>we will review the matter positively and follow up in person</color>...","TWN":"<color=#ffd34c>會積極考慮之後親自拜訪。</color>……"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그럼, 저건 여기에 연결하고...","JPN":"じゃあ、あれはここに繋いで……","ENG":"Okay, so this connects here...","TWN":"那把這個接在這裡……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_15"},{"id":"L15_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"이건... 어디에 꽂으면 되는 거지?","JPN":"これは……どこに刺せばいいの？","ENG":"And... where does this go?","TWN":"這個……要插在哪裡才好呢？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_10"},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"신경 연동망의 일종인 듯하군요. 아무데나 연결하면 감각의 위치가 바뀔 수도 있을 겁니다.","JPN":"神経連動網の一種のようですね。下手に繋ぐと感覚の場所が変わる可能性があります。","ENG":"It appears to be a type of neural linkage network. If connected incorrectly, the position of its sensory mapping may shift.","TWN":"看起來像是一種神經連動網。如果亂接可能會導致感覺位置錯亂。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L17_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"휴, 얼터니움에 물질 복원 기능이 있어서 다행이지. 이거라도 없었으면 이런 낯설고 이상한 장치들을 고치는 건 시늉도 못 했을 거야.","JPN":"ふう、オルタニウムに物質復元機能があってよかったよ。それもなかったら、こういう見たこともないヘンテコな装置を修理するなんて絶対無理。","ENG":"Whew. Good thing Alternium has material restoration functions. Without that, I wouldn't even know where to start fixing something this strange.","TWN":"呼，還好黑化永恆之金有物質復原功能，不然根本修不了這種陌生又奇怪的裝置。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그 타기리온이란 녀석한테 심하게 당하긴 한 모양이네. 오른쪽 어깨 접합부는 또 얼마나 망가졌는지...","JPN":"そのタギリオンってやつに派手にやられたみたいだね。右肩の接合部はひどい壊れようだし……","ENG":"Looks like that Thagirion really did a number on you. Just how badly was the right shoulder joint damaged...","TWN":"看來被塔基里翁打得很慘，右肩接合部位也壞得太嚴重了吧……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그건 제가 한 겁니다. 엘부르즈를 제대로 꽂아줬죠.","JPN":"それは私がやりました。アルボルズを完璧に刺してやりましたから。","ENG":"That was my doing. I inserted Alborz properly.","TWN":"那是我弄的。我把艾爾布勒茲狠狠插進去了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"네 네- 아주 잘 하셨어요.","JPN":"はいはい、お見事ですね～","ENG":"Yeah, yeah. You did a real great job.","TWN":"是、是—幹得漂亮。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그런데, 호라이즌. 아무리 얼터니움이라지만 이런 걸 복원해버려도 정말 괜찮을까? 나중에 마왕의 부하를 부활시켰다고 관리국이 우리도 잡아가는 거 아니겠지?","JPN":"でも、ホライズン。いくらオルタニウムでも、本当にこんなもん復元しちゃっていいの？　魔王の部下を復活させたって、後で管理局に捕まったりしない？","ENG":"Still, Horizon. Even if it's Alternium, is it really okay to restore something like this? The Administration isn't going to arrest us later for reviving one of a Demon Lord's grunts, right?","TWN":"不過地平線，就算有黑化永恆之金，修復這種東西真的沒問題嗎？之後不會被管理局以復活魔王部下為由抓走吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"...그녀는 마왕의 부하가 아닙니다. 클리파의 간섭에 얽매인 게 아니라, 언어로 입력된 명령에 따라 움직이던 인형일 뿐이죠.","JPN":"この人形……彼女は魔王の部下ではありません。クリファの干渉に縛られていたわけではなく、言語として入力された命令に従って動いていただけです。","ENG":"...She is not a grunt of a Demon Lord. She wasn't bound by Qlipha interference. She was merely a doll that acted according to commands entered through language.","TWN":"……她不是魔王的部下。她並不是受縛於逆卡巴拉的干涉，而是依照語言命令運作的人偶。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"하지만 자율의지를 가진 이상, 적어도 우리에게 해악을 끼칠 확률은...","JPN":"ですが自由意志を持つ以上、少なくとも私たちに害をなす確率は……","ENG":"However, now that she possesses autonomous will, the probability that she will cause harm to us is—","TWN":"但既然擁有自主意志，至少對我們造成危害的機率……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"꺅, 호라이즌이 날아갔어!","JPN":"きゃっ、ホライズンが飛んだ！","ENG":"Kyaah! Horizon!","TWN":"呀啊，地平線被打飛了！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"...라고 하자마자 믿음을 배반하고 공격할 줄은 몰랐군요.","JPN":"……と言ったそばから信用を裏切り、攻撃してくるとは。","ENG":"...I didn't expect her to betray my trust immediately after I said that.","TWN":"……沒想到才剛說完，就立刻背叛信任發動攻擊。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L30_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아직 전력도 안 공급했는데 왜 움직이지? 내가 신경을 잘못 건드렸나?","JPN":"まだ電源も繋いでないのに、なんで動くの？　アタシ、いじっちゃいけない神経をいじっちゃった？","ENG":"She's moving already? I haven't even supplied power yet. Did I touch the wrong connection?","TWN":"還沒供電怎麼就動了？是我接錯神經了嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"말했잖습니까. 인형이라고.","JPN":"言ったではないですか、人形だと。","ENG":"I told you. She is a doll.","TWN":"我不是說了嗎，這是人偶。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"여긴 어딥니까? 전 분명 타기리온과 싸우고 있었을 텐데요.","JPN":"ここはどこですか。タギリオンと戦っていたはずですが。","ENG":"Where is this place? I was certain I was fighting Thagirion.","TWN":"這裡是哪裡？我明明還在與塔基里翁戰鬥啊。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"타기리온과의 전투는 끝났습니다. 그리고 여긴 햄스워스 씨의 공방이죠.","JPN":"タギリオンとの戦闘は終わりました。そしてここはヘムズワースさんの工房です。","ENG":"The battle with Thagirion has ended. And this is Mr. Helmsworth's workshop.","TWN":"與塔基里翁的戰鬥已經結束了，而這裡是漢姆沃斯的工坊。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"출장에서 돌아온 그가 이 난장판을 봤을 때의 반응이 메모리에 훤하군요.","JPN":"出張から戻ってきた彼がこの惨状を見たときどんな反応をするか、メモリーに浮かぶようですね。","ENG":"His reaction when he returns from his trip and sees this mess is already vivid in my memory banks.","TWN":"等他出差回來看到這副慘狀，反應肯定很精彩。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"이렇게 생긴 곳이... 공방이란 겁니까?","JPN":"こんな場所が……工房だというのですか？","ENG":"A place like this... is called a workshop?","TWN":"這種地方……也能叫工坊？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"전말은 이해했습니다, 납치꾼들.","JPN":"顛末は理解しました、誘拐犯ども。","ENG":"I understand what's going on now, abductors.","TWN":"我理解事情經過了，綁架犯們。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"타기리온을 물리치고, 주인을 도와 탐미엘이란 신을 잡았더니 세계로 돌아갈 힘이 생겨서, 돌아오는 김에 저를 전리품처럼 챙겨왔다는 거군요.","JPN":"タギリオンを倒し、主を助けてタミエルという神を討ったら元の世界に戻る力ができ、戻るついでに私を戦利品のように持ってきたというわけですね。","ENG":"You defeated Thagirion, assisted my master in capturing the god called Tammiel, then regained the power to return to your world. And on your way back, you brought me along like spoils of war.","TWN":"你們打倒了塔基里翁，又協助主人抓住名為塔米爾的神，因此獲得了返回原世界的力量，順便把我當戰利品帶回來。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"그리곤 제가 가동되지 않는 원인을 파악하기 위해, 멋대로 제 몸을 주무르고 있었다- 정도로 이해하면 되겠습니까?","JPN":"そして私が稼働しない原因を把握するために、勝手に私の体をいじくっていた……という認識で問題ないでしょうか。","ENG":"Then, in order to determine why I wouldn't activate, you proceeded to tamper with my body at will. Is that an accurate summary?","TWN":"然後為了找出我無法啟動的原因，擅自對我的身體動手動腳—我理解的大致情況沒錯吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"음, 엄청 망가져 있어서 복원하느라 안쪽을 엄청 만지긴 했지. 구조는 달라도, 기능적인 부분은 호라이즌이랑 되게 비슷해서 놀랐달까?","JPN":"うーん、かなり壊れてたから、復元するために中身は結構いじったね。構造は違うけど機能的な部分はホライズンとかなり似てて驚いたよ。","ENG":"Well, you were pretty badly broken, so yeah, I had to open things up while restoring you. Even though your structure's different, some of the functional parts are surprisingly similar to Horizon's.","TWN":"嗯，因為壞得太嚴重了，修復時確實摸索不少內部。雖然構造不同，但功能跟地平線很像，讓我有點驚訝。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"비슷하다...? 저의 섬세한 소체가 이 무른 고철덩어리와 말입니까?","JPN":"似てる……？　私の繊細な素体が、この脆いくず鉄と、ですか？","ENG":"Similar...? You compare my delicate chassis to this soft lump of scrap metal?","TWN":"很像……？我精密的身體，怎麼可能和這種鬆散的廢鐵相提並論？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"오해가 있군요. 당신의 소체가 가진 특성은 섬세함이 아닌 단순함에 가깝습니다.","JPN":"誤解がありますね。あなたの素体の性質は繊細というより単純です。","ENG":"There is a misunderstanding. The defining characteristic of your chassis is not delicacy but simplicity.","TWN":"你誤會了。你的身體特性比較接近單純，而不是精密。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"어차피 어려운 용어는 당신의 단순한 처리 능력으론 알아듣지 못할 테니, 레이첼이 대신 쉽게 설명해주시죠.","JPN":"難しい用語で説明しても、どうせあなたの単純な処理能力では理解できないでしょう。代わりにレイチェルがわかりやすく説明してください。","ENG":"In any case, terminology beyond your processing capability would be wasted on you. Rachel, please explain it in simpler terms.","TWN":"反正困難的術語你也聽不懂，就讓瑞秋簡單說明吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아하하... 내가 비슷하다고 했던 건, 만들어진 소재가 아니라 기억을 담당하는 오파츠나 코어의 위치 같은 걸 말하는 거야.","JPN":"あはは……アタシが似てるって言ったのは素材じゃなくて、記憶を担当するオーパーツやコアの位置とかのことだよ。","ENG":"Ahaha... what I meant wasn't the material. I meant things like where the memory OOPArts or the core are positioned.","TWN":"哈哈……我說的很像，不是指製作的素材，而是負責記憶的歐帕茲或核心的位置之類的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아, 너희 세계의 부품들은 뭐라 불러야 할지 몰라서 일단 오파츠라고 부르고 있어.","JPN":"あ、そっちの世界でこういった部品をなんて呼ぶのか知らないから、とりあえずオーパーツって呼んでるんだけどね。","ENG":"Oh, I wasn't sure what to call the components from your world, so for now I've been calling them OOPArts.","TWN":"我們不知道你們世界的零件名稱，就先叫它歐帕茲了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"이 부분은... 기억 태엽이라고 부르면 됩니다.","JPN":"この部分は……記憶ゼンマイと呼びます。","ENG":"This component... is called a memory-spring.","TWN":"這部分……可以稱為記憶發條。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"오, 기억 태엽이구나. 부품 이름도 인형스럽네.","JPN":"へえ、記憶ゼンマイか。部品の名前も人形っぽいね。","ENG":"Oh, memory-spring. Even the part names sound doll-like.","TWN":"喔，記憶發條啊。名字也很有人偶風格呢。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"제가 원래 있던 곳으로 돌아갈 방법은 없습니까?","JPN":"私が元の世界に戻る方法はありませんか。","ENG":"Is there no way for me to return to where I came from?","TWN":"有辦法回到我原本的地方嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"제 기동목적은 낙원을 지키는 겁니다. 주인의 친구로서 말이죠.","JPN":"私の稼働目的は楽園を守ることです。主の友だちとして。","ENG":"My purpose is to protect the Promised Land. As my master's friend.","TWN":"我的任務是以主人的朋友身分守護樂園。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"으음... 돌아가는 건 어렵지 않을까? 거긴 엄청 먼 이면세계라서 돌아오는 데도 꽤 애먹었다고 들었거든.","JPN":"うーん……戻るのは難しいんじゃないかな？　そこはすごく遠い裏世界で、こっちに戻ってくるときも結構大変だったって聞いたから。","ENG":"Hmm... Going back might be difficult. I heard they had quite a hard time returning from there, since it's a very distant Counterside.","TWN":"嗯……要回去可能會很難吧？那裡是很遠的異界，我們回來也費了不少功夫。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"애초에 우린 당신을 납치한 게 아니라 주인의 데려가달라는 부탁을 받았을 뿐입니다.","JPN":"そもそも私たちはあなたを誘拐したのではなく、連れて行くようにあなたの主に頼まれただけです。","ENG":"To begin with, we did not abduct you. We were simply asked by your master to bring you with us.","TWN":"而且我們不是綁架你，是受你主人所託把你帶回來的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"주인...? 그녀가 당신에게 무슨 말을 했습니까?","JPN":"主……？　彼女があなたにどんなことを言ったのですか？","ENG":"My master...? What did she say?","TWN":"主人……？她對你們說了什麼？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"자신의 친구를 새로운 낙원으로 데려가 달라더군요.","JPN":"自分の友だちを新しい楽園に連れて行ってほしいと言っていました。","ENG":"She asked us to bring her friend to a new Promised Land.","TWN":"她說，希望把自己的朋友帶到新的樂園。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"참고로 새로운 낙원은 현실세계를 말하는 겁니다. ","JPN":"ちなみに新しい楽園とは、現実世界のことです。 ","ENG":"For reference, the new Promised Land refers to the Normalside. ","TWN":"順帶一提，新的樂園指的是現實世界。 "},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"...주인은 제가 명령 밖에 모르는 바보인 줄 아는군요. 이곳이 낙원이 아니라는 것쯤은 저도 압니다.","JPN":"……主は私のことを、命令しか知らないバカだと思っているのですね。ここが楽園ではないことくらい、私にも分かります。","ENG":"...She must think I'm a fool who understands nothing beyond orders. Even I know this place is not the Promised Land.","TWN":"……主人以為我是只會服從命令的笨蛋啊。我也知道這裡不是樂園。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"낙원이 사라졌으니. 저도 필요가 없어진 거겠죠.","JPN":"楽園が消えたから、私も必要なくなったのでしょう。","ENG":"That place is gone. Which means I am no longer needed.","TWN":"既然樂園消失了，也不需要我了吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"우울증에 걸리기 딱 좋은 부정적 사고방식이군요.","JPN":"うつ病になりやすいネガティブ思考ですね。","ENG":"That is a line of thinking well suited to developing depression.","TWN":"這種消極思考很容易得憂鬱症哦。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"저기, 반대로 생각해보는 건 어때?","JPN":"ねえ、逆に考えたらどう？","ENG":"Hey, what if you tried looking at it the other way around?","TWN":"欸，要不要換個角度思考？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"낙원이 정말 모두를 행복하게 해주는 곳이라면, 분명 그곳을 지키는 존재도 예외는 아닐 거야.","JPN":"楽園が本当にみんなを幸せにしてくれる場所なら、きっとそこを守る存在も幸せになれるはずだよ。","ENG":"If the Promised Land really was a place meant to make everyone happy, then the one protecting it wouldn't be an exception either.","TWN":"如果樂園真的是讓所有人幸福的地方，那守護它的存在也應該不例外。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"네 주인은 네가 행복하길 바랐기 때문에 이곳으로 보낸 거지.","JPN":"あんたの主はあんたを幸せにしたくて、ここに送ったの。","ENG":"Your master sent you here because she wanted you to be happy too.","TWN":"你的主人是希望你能幸福，才把你送來這裡的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"난 언젠가 완전한 낙원을 만들고 싶어.","JPN":"私はいつか完全な楽園を作りたい。","ENG":"I want to create the perfect Promised Land someday.","TWN":"我一直希望能創造出完整的樂園。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그러기 위해, 네가 우리와 함께 이 낙원을 지켜줬으면 해.","JPN":"そのために、私たちと一緒にこの楽園を守ってほしいの。","ENG":"So for that, I want you to protect this Promised Land with us.","TWN":"為此，我希望你能和我們一起守護這個樂園。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"주인에겐, 지금의 낙원이 아직 완전하지 않습니까?","JPN":"主にとって、今の楽園はまだ完全ではないのですか？","ENG":"Then is the Promised Land you have now still incomplete?","TWN":"主人的樂園……還不夠完整嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"내가 바라는 낙원은... 누구도 고통받지 않는 행복만이 있는 그런 편협한 곳이 아니야.","JPN":"私が思い描く楽園は……誰も苦しまない、幸せしかないそんな偏狭な場所じゃないよ。","ENG":"The Promised Land I desire... isn't a narrow place filled only with happiness where no one suffers.","TWN":"我理想中的樂園……不是只有幸福、沒有痛苦的狹隘之地。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"희망과 좌절, 기억과 망각, 삶과 죽음, 낮과 밤처럼 양면을 가졌기에 그 눈부심의 가치를 온몸으로 느낄 수 있는 완전한 세상.","JPN":"希望と挫折、記憶と忘却、生と死、昼と夜みたいに両面があるからこそ、その眩しさの価値を全身で感じ取れる完全な世界。","ENG":"It's a complete world where hope and despair, memory and forgetting, life and death, day and night all exist together so their brilliance can be truly felt.","TWN":"而是正因擁有希望與挫折、記憶與遺忘、生與死、白天與黑夜這些對立面，才能真正感受到其耀眼價值的完整世界。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"고향을 잃은 모든 존재들이 방랑 끝에 다다른 곳이, 난 그런 세상이었으면 좋겠어.","JPN":"故郷を失ったすべての存在が、流浪の末にたどり着く場所が、そんな世界だったらいいと思うんだ。","ENG":"A world where all those who lost their homes might finally arrive after their wandering ends. That's the kind of world I want.","TWN":"我希望那是一個讓所有失去故鄉的存在，在流浪之後能抵達的地方的那種世界。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"완전한... 낙원.","JPN":"完全な……楽園。","ENG":"The perfect... Promised Land.","TWN":"完整的……樂園。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신의 버려졌다는 부정적 사고방식을 강제로 뜯어고칠 생각은 없습니다. 저흰 심리상담사가 아니니까요.","JPN":"捨てられたと思うあなたのネガティブ思考を無理やり変えるつもりはありません。私たちはカウンセラーではないので。","ENG":"I have no intention of forcibly correcting your negative belief that you were abandoned. We are not psychological counselors.","TWN":"我們不是心理諮商師，我們不打算強行改變你覺得自己被拋棄的負面想法。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그녀의 바람대로 이곳이 당신을 행복하게 해줄 낙원이 될지는, 당신이 받아들이기에 달렸겠죠.","JPN":"彼女の望み通り、ここがあなたを幸せにする楽園になるかどうかは、あなたの受け取り方次第です。","ENG":"Whether this place becomes the Promised Land she wished for you depends on whether you choose to accept it.","TWN":"這裡能不能如她所願成為讓你幸福的樂園，取決於你自己是否願意接受。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"...납득했습니다.","JPN":"……納得しました。","ENG":"...I understand.","TWN":"……我明白了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"이곳에서 저를 처음으로 기동한 건 당신들이니, 저에게 과업을 맡겨주십시오.","JPN":"私を初めて稼働させたのはあなたたちですから、私に任務を与えてください。","ENG":"You were the ones who activated me. Please assign me a task.","TWN":"既然是你們重新啟動了我，那就請交給我任務吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"...그렇다고 하는군요, 레이첼.","JPN":"……だそうです、レイチェル。","ENG":"...So she says, Rachel.","TWN":"……她這麼說呢，瑞秋。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"응? 그래, 그럼 이거 받아.","JPN":"そう？　じゃあこれ受け取って。","ENG":"Oh? All right then. Here, take this.","TWN":"嗯？好，那這個給你。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"이 묵직한 중량감... 단단한 경도와 칼날 같은 예리함... 틀림없는 무기로군요.","JPN":"このずっしりとした重さ……硬度の高さと刃物のような鋭さ……紛れもなく武器ですね。","ENG":"This weight... This firmness... This sharp edge like a blade... It's unquestionably a weapon.","TWN":"這個重量感……堅硬的材質與鋒利的邊緣……毫無疑問是武器。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"이걸로 어떤 마물을 처리하면 되는 겁니까?!","JPN":"これでどういう魔物を仕留めればいいのですか！？","ENG":"What monster am I to eliminate with this?!","TWN":"是要我用這個消滅什麼魔物嗎？！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"시멘트삽입니다. 이걸로 당신이 무너뜨린 벽면을 복구하십시오.","JPN":"それはコテです。それであなたが壊した壁を修復してください。","ENG":"It is a cement shovel. Use it to repair the wall you destroyed.","TWN":"這是水泥鏟，請用這個來修復剛剛被你破壞的牆壁。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"엑.","JPN":"えっ。","ENG":"Eh?","TWN":"咳。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신의 낙원에선 뭘 때려부숴도 알아서 고쳐졌겠지만, 여긴 그렇지 않습니다.","JPN":"あなたの楽園では何をぶち壊しても勝手に修復されたでしょうけど、ここは違います。","ENG":"In your Promised Land, anything you broke likely repaired itself automatically. That isn't the case here.","TWN":"在你的樂園，雖然東西壞了會自己修好，但這裡不是如此。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이곳에선 자신의 손으로 부순 건, 자신이 고치는 게 기본 규칙이죠. 금방 적응할 수 있을 겁니다.","JPN":"自分が壊したものは自分で直す、それがここの基本的なルールです。すぐ適応できます。","ENG":"Here, the basic rule is that whatever you break with your own hands, you fix. You will adapt quickly.","TWN":"在這裡，自己破壞的東西就要自己修復。你很快就會習慣的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"서둘러! 햄스워스 씨가 돌아오기 전에 끝내는 거야!","JPN":"急いで！　ヘムズワースさんが帰って来る前に終わらせるんだよ！","ENG":"Hurry! We have to finish before Mr. Helmsworth gets back!","TWN":"快點！在漢姆沃斯回來之前弄好！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L45_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"벌써 당신이 그립군요, 주인.","JPN":"早くもあなたが恋しくなりました、主。","ENG":"I already miss you, Master.","TWN":"我已經開始想念你了，主人。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"그래도 이게 친구의 바람이라면 견뎌보도록 하죠.","JPN":"ですが、これが友だちの願いだというのなら……耐えてみます。","ENG":"Still, if this is the wish of my friend, I will endure it.","TWN":"但既然這是朋友的願望，我會努力撐下去。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"언젠가, 다시 만날 그날을 기다리겠습니다.","JPN":"いつかまた会える日を待っています。","ENG":"I will wait for the day we meet again.","TWN":"我會等待我們再次相見的那一天。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};